export type NotoSansWeight = "100" | "200" | "300" | "400" | "500" | "600" | "700" | "800" | "900";
export type NotoSansStyle = "italic" | "normal";
export type NotoSansSubset = "cyrillic" | "cyrillic-ext" | "devanagari" | "greek" | "greek-ext" | "latin" | "latin-ext" | "vietnamese";
export type NotoSansOptions = GoogleFontOptions<NotoSansWeight, NotoSansStyle, NotoSansSubset>;

/**
 * Noto Sans — Google font. Pass `weights`/`styles` to register a subset of
 * faces (omit for all) and `subset` to choose the character set (default "latin").
 */
export default class NotoSans extends GoogleFont<NotoSansWeight, NotoSansStyle, NotoSansSubset> {
  constructor(options?: NotoSansOptions) {
    super(FAMILY, FACES, options);
  }
}
